var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"무리야, 이 기름 덩어리를 어떻게 다 치워?","JPN":"無理だよ。こんな油の量をどうやって回収すればいいの？","ENG":"This is impossible. How am I supposed to clean up all this oil?","TWN":"不行啦，怎麼可能有辦法把油漬全都清乾淨？"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"나 혼자서는 오늘 하루 종일 해도 안 끝날 것 같은데…….","JPN":"私一人じゃ一日中掃除しても終わらない……","ENG":"I won't be able to finish it by today if I do this alone...","TWN":"我一個人清一整天也清不完吧……"},"stage":{"bg":"SUMMER_SWIMPOOL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"미안해. 결국 사진은 못 찾았어.","JPN":"ごめんね、写真部のみんな。\\n結局写真は見つけることが出来なかった。","ENG":"Sorry. I couldn't find your photos.","TWN":"對不起，結果還是沒找到照片。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"응? 어떻게든 전시회를 열 수 있는 방법?","JPN":"えっ？　なんとか展示会を実施できる方法？","ENG":"Hmm? A way to still hold the exhibition?","TWN":"嗯？還有什麼方法可以舉行攝影展嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"미안…… 나는 어떻게 해야 할지 잘 모르겠어…….","JPN":"ごめんなさい……私にはいい方法が思いつかなくて……","ENG":"Sorry... But I'm not sure what to do...","TWN":"抱歉……我想不到方法……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아무리 합을 맞추고 진행한다고 해도 검을 다루는 일은 매우 위험하죠.","JPN":"事前に打ち合わせをするとしても、剣を扱うのはとても危険なことです。","ENG":"Even if everything is choreographed, handling a real sword on stage is dangerous.","TWN":"不過就算我願意配合你們，但畢竟刀劍無眼，還是有危險性的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"유감스럽지만, 저와 동등한 실력자가 없다면 이 제안은 받아들일 수 없군요.","JPN":"申し上げにくいですが、\\n私と同等の実力者がいないのなら、この提案を引き受けることはできません。","ENG":"I'm sorry, but I cannot accept this part unless the other actor is as skilled with swords as I am.","TWN":"很抱歉，若是沒有與我實力相當的對手，請恕我無法答應。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"어이, 들었어? 학원제에 불참하게 된 동아리가 늘고 있대. 학생회에 도움을 요청했는데도 해결이 안 됐다나 봐.","JPN":"おい、聞いたか？　いくつかの部の出し物が中止になったらしい。\\n生徒会にトラブルの報告をしていたにも関わらずだってさ。","ENG":"Hey, did you hear? More and more clubs are withdrawing from the festival. Something about not getting their problems solved even though they asked the Student Council for help.","TWN":"喂喂，你們有聽說嗎？聽說越來越多社團不參加學園祭欸。看來就算求助於學生會也沒用。"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"학생회 녀석들은 뭘 하고 있는 거야? 학원제 관리가 전혀 되고 있지 않잖아.","JPN":"生徒会はちゃんと仕事してるの？\\n学園祭の管理が全然できてないじゃない。","ENG":"What is the Student Council even doing? It's like they're not even trying to supervise the festival.","TWN":"學生會的人是在做什麼？連個學園祭都搞不定！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"역대 최악의 학생회와 역대 최악의 학원제야. 진짜.","JPN":"歴代最悪の生徒会に歴代最悪の学園祭だよ、まったく。","ENG":"This year has the worst Student Council and the worst festival ever, really.","TWN":"這根本是歷年來最糟最慘的學園祭，真是的！"},"stage":{"bg":"GEASS_ASHFORD","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그러니까…….","JPN":"つまり……","ENG":"So...","TWN":"現在……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"수영장에 떠다니는 기름의 악취가 퍼져서, 부스를 닫아야 하는 동아리가 계속 나오고 있고.","JPN":"プールに浮いていた油の悪臭が広がり、\\n中止を余儀なくされた他の部の屋台が続出していて……","ENG":"Due to the foul stench emanating from the blobs of oil in the pool, an increasing number of clubs have closed their booths.","TWN":"因為泳池的油漬惡臭飄出來，導致有越來越多的社團的攤位必須關閉。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"사진을 잃어버린 사진부는 전시관에서 미술품을 훼손하다가 싸움이 일어났으며…….","JPN":"展示写真をなくした写真部は、会場で美術部の展示品を壊して大喧嘩になり……","ENG":"After having their photos stolen, the photography club attempted to sabotage the art club's works and got into a fight...","TWN":"而照片不見的攝影部，則是因為破壞展覽館裡的美術品，導致雙方發生衝突……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"연극부에서는 동아리 내부 균열로 폐부 위기……라는 말인가요?","JPN":"演劇部では部内の対立によって廃部の危機に……ということですか？","ENG":"And the theater club is on the brink of disbanding due to internal conflict... Correct?","TWN":"戲劇部因為內鬨，吵到快要……廢社？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생들의 안전을 생각한 일이었는데…… 일이 이렇게 될 줄은 몰랐군요.","JPN":"生徒たちの安全のために務めてきたつもりでしたが……\\nこんなことになるとは。","ENG":"I was prioritizing everyone's safety... but I never imagined things would end up like this.","TWN":"原本只是顧慮到學生的安全……沒想到事情會變成這樣。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KALLEN_NPC_GEASS_NULL","text":{"KOREA":"미안, 최선을 다했는데…….","JPN":"ごめん。ベストは尽くしたんだけど……","ENG":"Sorry, I tried my best, but...","TWN":"對不起，我已經盡力了……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"SHIRLEY_NPC_GEASS_NULL","text":{"KOREA":"나 혼자서는 문제를 제대로 해결하지 못했어……. 미안해 루루.","JPN":"上手くトラブルを解決できなかった……ごめんね、ルル。","ENG":"I couldn't resolve the issue on my own... I'm sorry, Lulu.","TWN":"光靠我自己一個人沒辦法解決問題……對不起，魯魯。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KALLEN_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SHIRLEY_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아니. 학원제가 이렇게 된 건 학생회인 너희들 때문이 아니야.","JPN":"いや、学園祭がこうなってしまったのは生徒会のみんなのせいではない。","ENG":"No. It is not your fault the festival ended up like this.","TWN":"不，學園祭會變成這樣，不是你們的問題。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"진짜 원인은 실행위원장인 내 역량부족이겠지. 미안하다.","JPN":"一番の原因は、学園祭実行委員長である俺の力不足だ。すまない。","ENG":"It's my incompetence as the head of the executive committee. My apologies.","TWN":"而是身為執行委員長的我辦事不力，我很抱歉。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥! 사과한다고 뭐가 달라져?","JPN":"ふん！　謝っても意味がないわ！","ENG":"Hmph! Like your apology is gonna change anything!","TWN":"哼！道歉有用嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"학생회 전체 평판이 바닥으로 떨어졌는데 이제와서 어떻게 책임질 건데?","JPN":"生徒会全体の評判が地に落ちたのに、今さらどうやって責任を負うつもり？","ENG":"The Student Council's reputation is in the gutter. How are you going to make up for that?","TWN":"現在學生們對於學生會的評價已經跌落谷底，你要怎麼負責？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"나이엘 양, 그만해요. 누군가를 추궁해서 해결될 문제가 아니잖아요.","JPN":"ナイエルさん、やめましょう。誰かを責めても解決にはなりませんよ。","ENG":"Naielle, enough is enough. Interrogating others won't solve the issue.","TWN":"奈爾，別這樣，現在就算找個人來背黑鍋問題也不會解決。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아니, 그만 하긴 뭘 그만해?","JPN":"いいえ、何をやめるっていうのよ？","ENG":"What do you mean, enough is enough?","TWN":"什麼別這樣？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우리가 캠프파이어를 준비하는 동안, 이 녀석들은 맡은 일도 똑바로 못해서 학원제가 엉망이 된 거잖아!?","JPN":"だって、こいつらが任された仕事ができなかったせいで、\\n学園祭が台無しになったのよ！　私たちはちゃんと後夜祭の準備をしていたのに！","ENG":"The festival's ruined because they couldn't do their jobs while we were preparing the campfire!","TWN":"我們在準備營火的這段時間，他們沒有把該辦的事辦好，才會害學園祭毀掉的不是嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그것도 하필 우리가 올해의 학년 대표일 때 말이야! 선배는 억울하지도 않아!?","JPN":"しかも、よりによって私たちが学年代表の時にね！　先輩は悔しくないの？","ENG":"And to ruin it on the year that we're the student representatives! Isn't that so unfair, Tapir?!","TWN":"然後還偏偏挑在我們當學生代表的時候！前輩你不覺得很冤枉嗎？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"진정해 나이엘. 모두들 최선을 다했지만 어쩔 수 없는 일이잖아. 이제 그만하자.","JPN":"落ち着いて、ナイエル。\\nみんな、ベストを尽くしたけど、解決できなかったんだもの。もうやめよう。","ENG":"Naielle, calm down. Everyone did their best, and there's nothing we can do about how things turned out. So just let it go.","TWN":"奈爾，你冷靜點。大家都盡力了，只是結果不如預期，你就別說了。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"뭐야, 너는 또 뭔데 끼어들어, 전학생?","JPN":"はあ？　あんた何様のつもり？　割り込んでこないで、転校生！","ENG":"Who're you to butt in, transfer student?","TWN":"什麼東西，轉學生你算老幾，憑什麼插嘴？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 열심히 준비하고 또 노력해도 우리 뜻대로 안 되는 일도 있어.","JPN":"どんなにがむしゃらに努力して準備したって、思いどおりにならないこともある。","ENG":"Some things are just out of our control, no matter how much we try.","TWN":"即使我們再努力、再認真預備，有些事本來就無法盡如人意。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 결과가 안 좋았다고 해서 우리끼리 잘잘못을 탓하면서 싸우고 싶지는 않아.","JPN":"でも、結果が良くなかったからって、\\nお互いのせいにしてケンカなんてしたくない。","ENG":"But that doesn't mean we should hold each other responsible for the bad outcomes.","TWN":"但我不希望因為結果不如預期，我們就互相責怪、爭吵。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"왜냐하면…… 학원제 같이 특별한 날이 아니더라도, 우리는 원래부터 진짜 친구잖아. 안 그래, 회장? 나이엘?","JPN":"だって……学園祭みたいな特別なイベントがなくても、\\n私たちは元から本当の友達じゃない。そうでしょ、会長？　ナイエルも。","ENG":"Because... whether or not it's a special occasion like the school festival, we're still true friends. Isn't that right, Yen? Naielle?","TWN":"因為……就算沒有學園祭，我們本來就是朋友不是嗎？會長？奈爾？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L1_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇군요. 잠시 잊고 있었습니다. 애쉬포드 학원제는 조화와 화합의 학교 축제죠.","JPN":"そうですね。忘れてしまっていたようです。\\nアッシュフォード学園祭は調和と和合の学園祭です。","ENG":"You're right. It must have slipped my mind. Ashford's festival is all about harmony and balance.","TWN":"沒錯，我差點忘了，阿什弗德學園祭的重點就是同樂。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 오히려 이 축제로 하여금 학생들이 다투게 된다면, 학원제는 차라리…….","JPN":"しかし、むしろその祭りが生徒たちの諍いの原因になるのなら、\\nいっそのこと学園祭は……","ENG":"But if this festival is causing students to fight with each other, then it would be better to...","TWN":"若是學生們反而因為學園祭而起爭執，那不如乾脆……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자, 잠깐만……!!","JPN":"ま、待って……！！","ENG":"W-wait...!!","TWN":"等，等一下……！！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"회장, 설마 내일 학원제를 중지할 생각이야?","JPN":"会長、まさか学園祭を中止するつもりなの？","ENG":"You're not thinking of canceling the festival, are you?","TWN":"會長，你該不會是要取消明天的學園祭吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"난 인정 못해! 인정 못한다구! 이렇게 허무하게 학원제가 끝나게 내버려 둘 것 같아!?","JPN":"認めない！　絶対に認められないっての！\\nせっかく準備を進めてたのに、学園祭をやらないだなんて私は認めない！","ENG":"I refuse to accept this! This is unacceptable! Do you think I'm going to let the festival just end like that?!","TWN":"我不答應！我不准！我不允許學園祭就這樣莫名取消！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"마지막까지 포기하지 않으면 어떻게 될지 모르는 거잖아!","JPN":"最後まで諦めなければ、どうなるかわからないでしょ！","ENG":"Maybe we can make things work if we keep trying!","TWN":"只要堅持到最後不放棄，結果會怎樣還不一定呢！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이제 와서 그만두자는 헛소리할 시간이 있으면……","JPN":"今更やめようなんて馬鹿な事を言ってる暇があるなら……","ENG":"If you have the time to complain and talk about quitting...","TWN":"你們有時間在這邊說要取消……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"다들 내 캠프파이어나 도우라구우우우!!","JPN":"みんな私のキャンプファイヤーを手伝ってよおおお！！","ENG":"Then use that time to help with my campfire insteeeaaaad!!!","TWN":"那不如來幫我準備營火啦！！！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘…….","JPN":"ナイエル……","ENG":"Naielle...","TWN":"奈爾……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 양…….","JPN":"ナイエルさん……","ENG":"Naielle...","TWN":"奈爾……"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"그렇군. 나이엘의 말이 맞아.","JPN":"そうだな。ナイエルの言うとおりだ。","ENG":"Yes, Naielle is right.","TWN":"沒錯，奈爾說的對。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"아직 올해의 학원제는 끝나지 않았어.","JPN":"まだ学園祭のために出来ることはある。","ENG":"This year's festival isn't over yet.","TWN":"今年的學園祭還沒結束！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LELOUCH_NPC_GEASS_NULL","text":{"KOREA":"지금이라도 모두 힘을 합쳐 캠프파이어를 멋지게 성공시킨다면, 적어도 올해 학원제가 최악이라는 말은 듣지 않을 거야.","JPN":"今からでもみんなで力を合わせて後夜祭を成功させれば、\\n少なくとも今年の学園祭が最悪だったなんて言われないだろう。","ENG":"If we all work together and successfully light the campfire, at least people won't say it's the worst festival ever.","TWN":"只要大家一起合力打造出一個絢爛的營火，至少可以消除最糟學園祭的污名吧？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LELOUCH_NPC_GEASS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"최악? 무슨 소리를 하는 거야, 를르슈!!","JPN":"最悪？　何を言ってるの、ルルーシュ！！","ENG":"Worst festival ever? What are you talking about, Lelouch?!","TWN":"最糟？你在說什麼，魯路修！！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"우리 두 사람이 학년 대표인 학원제가 최악일 리 없잖아?","JPN":"私たち二人が学年代表なのに、今年の学園祭が最悪なわけがないじゃない！","ENG":"Tapir and I are this year's student representatives! There's no way this festival's going to be the worst ever!","TWN":"有我們二個學生代表在的學園祭怎麼可能是最糟的！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"안 그래, 타피르 선배?","JPN":"そうだよね、タピル先輩？","ENG":"Isn't that right, Tapir?","TWN":"你說是不是，達爾前輩？"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"TAPIR_NPC_GEASS_NULL","text":{"KOREA":"맞아요, 나이엘 양 말대로 포기하긴 아직 일러요.","JPN":"ええ、ナイエルさんの言うとおり、諦めるにはまだ早いです。","ENG":"Yes. Like Naielle said, we can't give up yet.","TWN":"沒錯，就像奈爾說的，現在還不是放棄的時候。"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"자, 다들 알아들었으면, 빨랑빨랑 움직여!","JPN":"さあ、みんなわかったなら、さっさと動いて！","ENG":"Now that all of you understand, let's get a move on it!","TWN":"好，大家都聽到了吧，那還不趕快動起來！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"이 나이엘 님의 새로운 필살기로 얼어붙은 학원제 분위기를 한번에 띄워주겠어!!","JPN":"このナイエル様が新しい必殺技で\\n冷めきった学園祭の雰囲気を一気に盛り上がらせてやるんだから！！","ENG":"I, Naielle, will use my new special skill to liven up this dead festival's atmosphere!!","TWN":"奈爾我要用新的必殺技把冷掉的學園祭氣氛給炒熱起來！！"},"stage":{"bg":"GEASS_ROOM","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"TAPIR_NPC_GEASS_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};